// Если модель возвращает [{"output": {...}}]
const item = $json[0] || $json; // берём первый элемент, если это массив
return [ item.output || item ];

// Вход = весь body вебхука.
// В n8n он может быть в $json.body (если Webhook вернул {"body": [...]})
// или прямо в $json (если он сразу массив). Обработаем оба варианта.

const payload = Array.isArray($json.body) ? $json.body : $json;

if (!Array.isArray(payload)) {
  // если пришла не пачка, а один объект — всё равно делаем массив из него
  return [ payload ];
}

// Превращаем каждый элемент массива в отдельный item
return payload.map(replica => {
  return {
    json: replica
  };
});

// Берём входной batch (из Aggregate или напрямую)
const batch = $json.items || $json.data || [];

let lastOpponent = null;

// ищем последнюю реплику оппонента
for (const r of batch) {
  if (r.metadata && r.metadata.speaker === 'opponent') {
    lastOpponent = r;
  }
}

// если не нашли оппонента — выходим
if (!lastOpponent) {
  return [
    {
      json: {
        hasOpponent: false,
        hasOpponentQuestion: false,
        Question: null,
        sessionId: null,
      },
    },
  ];
}

// текст реплики
const text = String(lastOpponent.pageContent || "").trim();

// ----------------------------
// Проверка: есть ли вопросительный знак
// ----------------------------
const isQuestion = /[?？]/.test(text);

// ----------------------------

return [
  {
    json: {
      hasOpponent: true,
      hasOpponentQuestion: isQuestion,
      Question: text,
      sessionId: lastOpponent.metadata.session_id || null,
    },
  },
];

// Нормализация ответа агента к целевому виду
// 1) Берём output из массива/объекта
const raw = Array.isArray($json) ? $json[0] : $json;
const base = raw?.output ?? raw ?? {};

// 2) Прокидываем исходный вопрос из входа узла-агента
// (если вопрос приходит из предыдущего item, он уже в $json.Question на входе агента.
// Чтобы подстраховаться, берём из текущего контекста, если есть)
const question = base.Question ?? $json.Question ?? $items(0,0).json?.Question ?? "";

// 3) Собираем гарантированную структуру
return [
  {
    json: {
      message_type: "question",
      Question: question,
      answer: base.answer ?? base.text ?? base.response ?? "N/A"
    }
  }
];

const output = [];

for (const item of $input.all()) {
  const binaries = item.binary || {};
  for (const [key, data] of Object.entries(binaries)) {
    output.push({
      json: {
        field: key,
        fileName: data.fileName,
        mimeType: data.mimeType,
        fileExtension: data.fileExtension,
        fileSize: data.fileSize,
      },
      binary: { data },
    });
  }
}

return output;

// Берём все входные items
const items = $input.all();

// sessionId берём из первого item, где он есть
const sessionId =
  items.find(i => typeof i.json.sessionId === 'string')?.json.sessionId ?? null;

// Собираем все текстовые поля
const texts = items
  .map(i => i.json.text)
  .filter(t => typeof t === 'string' && t.trim() !== '');

// Возвращаем один item с объединённым текстом и sessionId
return [
  {
    json: {
      sessionId,
      mergedText: texts.join('\n\n')
    }
  }
];

// Если модель возвращает [{"output": {...}}]
const item = $json[0] || $json; // берём первый элемент, если это массив
return [ item.output || item ];

