{
  "type": "object",
  "properties": {
    "report": {
      "type": "object",
      "properties": {
        "strategy_result": {
          "type": "string",
          "enum": ["достигли", "не достигли"],
          "description": "Итог по стратегии: достигли ли целей стратегии."
        },
        "strategy_explanation": {
          "type": "string",
          "description": "Краткое фактическое объяснение, почему такой результат по стратегии."
        },
        "deal_success_result": {
          "type": "string",
          "enum": ["достигли", "не достигли"],
          "description": "Итог по критериям успеха сделки."
        },
        "deal_success_explanation": {
          "type": "string",
          "description": "Краткое фактическое объяснение, почему такой результат по успеху сделки."
        },
        "strategy_feedback": {
          "type": "array",
          "description": "Список наблюдений: что было сделано правильно/неправильно в рамках стратегии.",
          "items": {
            "type": "string"
          }
        },
        "future_success_advice": {
          "type": "array",
          "description": "Практические советы, как повысить шансы успеха в будущих переговорах.",
          "items": {
            "type": "string"
          }
        }
      },
      "required": [
        "strategy_result",
        "strategy_explanation",
        "deal_success_result",
        "deal_success_explanation",
        "strategy_feedback",
        "future_success_advice"
      ],
      "additionalProperties": false
    }
  },
  "required": ["report"],
  "additionalProperties": false
}

